import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Airship Configuration","description":"","frontmatter":{"title":"Airship Configuration","slug":"airship-configuration"},"headers":[],"relativePath":"developer-hub/airship-configuration.md","filePath":"developer-hub/airship-configuration.md"}'),o={name:"developer-hub/airship-configuration.md"};function n(s,e,h,l,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Airship creates deeper connections with customers by delivering incredibly relevant, orchestrated messages on any channel.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and providing your relevant Ids will result in Branch automatically forwarding referred events to Airship, in the exact format Airship expects.</p><h3 id="branch-events-sent-to-airship" tabindex="-1">Branch Events Sent to Airship <a class="header-anchor" href="#branch-events-sent-to-airship" aria-label="Permalink to &quot;Branch Events Sent to Airship&quot;">​</a></h3><p>The events Branch sends to third party data tools varies based on the events the partner supports as well as whether or not you&#39;ve implemented the Branch SDK to measure said events.</p><p>Airship supports the following events:</p><ul><li>Commerce Events</li><li>Custom Events</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Airship, you need to have completed the following:</p><ol><li><p>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have the Advanced Data Feeds add-on enabled on your Branch account. Advanced Data Feeds can be included as an add-on to both the Engagement and Performance <a href="./packaging.html">products</a>.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p><a href="https://docs.airship.com/platform/" target="_blank" rel="noreferrer">Implement the Airship SDK</a></p><ul><li>Make sure to follow the steps in Airships <a href="https://docs.airship.com/partners/branch/#associating-branch-events-with-airship-channels" target="_blank" rel="noreferrer">documentation here</a>.</li></ul></li><li><p>Admin access to your Airship account.</p></li></ol><h2 id="enable-airship" tabindex="-1">Enable Airship <a class="header-anchor" href="#enable-airship" aria-label="Permalink to &quot;Enable Airship&quot;">​</a></h2><h2 id="_1-retrieve-ids-from-airship" tabindex="-1">1. Retrieve IDs from Airship <a class="header-anchor" href="#_1-retrieve-ids-from-airship" aria-label="Permalink to &quot;1. Retrieve IDs from Airship&quot;">​</a></h2><p>Before you can enable the integration in your Branch dashboard, you need to retrieve your credentials from your Airship account.</p><p>Branch requires these credentials to not only authenticate, but to ensure your Branch data is being sent to the correct account.</p><p>Branch requires the following credentials:</p><ul><li>Airship Project Domain</li><li>Application Key</li><li>Access Token</li></ul><p>Please refer to <a href="https://docs.airship.com/" target="_blank" rel="noreferrer">Airship&#39;s documentation</a> if you need instructions on how to find the values required to enable the integration.</p><h2 id="_2-connect-airship-in-branch" tabindex="-1">2. Connect Airship in Branch <a class="header-anchor" href="#_2-connect-airship-in-branch" aria-label="Permalink to &quot;2. Connect Airship in Branch&quot;">​</a></h2><p>In the Branch Dashboard in Data Feeds → <a href="https://dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer"><strong>Data Integrations</strong> tab</a>, find and search for Airship.</p><p>Enter the IDs from the previous step. Enter them into the iOS and Android fields in the Branch Dashboard, and hit <strong>Save</strong>.</p><h2 id="_3-pass-metadata-to-the-branch-sdk" tabindex="-1">3. Pass Metadata to the Branch SDK <a class="header-anchor" href="#_3-pass-metadata-to-the-branch-sdk" aria-label="Permalink to &quot;3. Pass Metadata to the Branch SDK&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Developer Required</p><p>Developers on your mobile app are required for this step</p></div><p>Airship requires you to pass through the correct identifiers to the Branch SDKs. In order to do so, retrieve the ID from the Airship SDK and pass this value to Branch using the following method:</p><ul><li><code>setRequestMetadataKey()</code> method of the Branch SDKs:</li></ul><div class="danger custom-block"><p class="custom-block-title">IMPORTANT</p><p>To be able to match events with your users - you must send a client&#39;s email using <strong>$airship_user_id</strong> metadata key in via <strong>.setRequestMetaData</strong></p></div><h2 id="_4-verify-data-sent" tabindex="-1">4. Verify Data Sent <a class="header-anchor" href="#_4-verify-data-sent" aria-label="Permalink to &quot;4. Verify Data Sent&quot;">​</a></h2><p>Once the above steps are complete, you are now ready to start launching campaigns. Branch-attributed conversions will be sent to Airship. To verify data is being sent from Branch to Airship, you can look at the Branch Dashboard&#39;s <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>webhook partner key</td><td>equals</td><td>di_airship</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Wait Period</p><p>Please be patient as data may take some time to flow through Branch&#39;s attribution systems and onto Airship. If data has not appeared in Airship after 30 minutes of completing a test conversion, review the above steps to see if you may have missed something.</p></div>',31)])])}const b=a(o,[["render",n]]);export{u as __pageData,b as default};
